type RenderDeployStatusEntry = {
  id?: string;
  status?: string;
  trigger?: string;
  createdAt?: string;
  finishedAt?: string | null;
  commit?: { id?: string; message?: string } | null;
  failureReason?: string | null;
};

async function readRenderCreds(): Promise<{ apiKey: string; serviceId: string }> {
  const apiKey = (process.env.RENDER_API_KEY ?? '').trim() || await getIVXOwnerVariableRuntimeValue('RENDER_API_KEY');
  const serviceId = (process.env.RENDER_SERVICE_ID ?? '').trim() || await getIVXOwnerVariableRuntimeValue('RENDER_SERVICE_ID');
  return { apiKey, serviceId };
}

async function pollRenderDeploy(apiKey: string, serviceId: string, deployId: string, maxMs: number): Promise<{ entry: RenderDeployStatusEntry | null; pollCount: number; terminal: boolean }> {
  const deadline = Date.now() + maxMs;
  let pollCount = 0;
  let entry: RenderDeployStatusEntry | null = null;
  while (Date.now() < deadline) {
    pollCount += 1;
    try {
      const r = await fetch(`https://api.render.com/v1/services/${encodeURIComponent(serviceId)}/deploys/${encodeURIComponent(deployId)}`, {
        headers: { Authorization: `Bearer ${apiKey}`, Accept: 'application/json' },
      });
      if (r.ok) {
        const data = await r.json().catch(() => null) as RenderDeployStatusEntry | null;
        if (data) entry = data;
        const status = String((data?.status ?? '')).toLowerCase();
        const terminalStates = ['live', 'deactivated', 'build_failed', 'update_failed', 'canceled', 'pre_deploy_failed'];
        if (terminalStates.some((s) => status.includes(s))) return { entry, pollCount, terminal: true };
      }
    } catch {
      // network blip — keep polling
    }
    await new Promise((res) => setTimeout(res, 5000));
  }
  return { entry, pollCount, terminal: false };
}

async function probeProductionHealth(): Promise<{ baseUrl: string | null; status: number | null; ok: boolean; marker: string | null; error: string | null; durationMs: number }> {
  const baseUrl = (process.env.PRODUCTION_BASE_URL ?? '').trim() || 'https://api.ivxholding.com';
  const started = Date.now();
  try {
    const r = await fetch(`${baseUrl.replace(/\/$/, '')}/health`, { method: 'GET' });
    let marker: string | null = null;
    try {
      const j = await r.json() as Record<string, unknown>;
      if (typeof j?.deploymentMarker === 'string') marker = j.deploymentMarker;
      else if (typeof j?.marker === 'string') marker = j.marker;
    } catch {
      // body may be plain text — ignore
    }
    return { baseUrl, status: r.status, ok: r.ok, marker, error: null, durationMs: Date.now() - started };
  } catch (err) {
    return { baseUrl, status: null, ok: false, marker: null, error: err instanceof Error ? err.message : 'network_error', durationMs: Date.now() - started };
  }
}

/**
 * POST /api/ivx/autonomy/deploy/approve-and-run
 *
 * One-tap autonomous owner-approved deploy. Verifies the signed-in owner via
 * the Supabase bearer attached to the request, triggers a Render deploy of
 * the latest commit, polls until terminal status, then probes production
 * `/health`. Returns full proof. Never echoes secrets.
 *
 * Body: { clearCache?: boolean; pollTimeoutMs?: number }
 */
export async function handleIVXAutonomyDeployApproveAndRunRequest(request: Request): Promise<Response> {
  const startedAt = new Date().toISOString();
  try {
    const ownerContext = await assertIVXOwnerOnly(request);
    const body = readObjectInput(await request.json().catch(() => ({})));
    const clearCache = body.clearCache === true ? 'clear' : 'do_not_clear';
    const pollTimeoutMs = typeof body.pollTimeoutMs === 'number' && Number.isFinite(body.pollTimeoutMs)
      ? Math.min(Math.max(body.pollTimeoutMs, 30_000), 8 * 60_000)
      : 5 * 60_000;

    const { apiKey, serviceId } = await readRenderCreds();
    if (!apiKey || !serviceId) {
      return ownerOnlyJson({
        ok: false,
        marker: IVX_AUTONOMY_MARKER,
        stage: 'preflight',
        error: 'missing_render_credentials',
        renderApiKeyConfigured: Boolean(apiKey),
        renderServiceIdConfigured: Boolean(serviceId),
        hint: 'Backend runtime cannot read RENDER_API_KEY / RENDER_SERVICE_ID from env or Owner Variables.',
      }, 503);
    }

    const ownerEmail = typeof ownerContext.email === 'string' ? ownerContext.email : null;
    const ownerEmailMasked = ownerEmail
      ? `${ownerEmail.slice(0, 2)}***@${ownerEmail.split('@')[1] ?? 'unknown'}`
      : null;
    const approvalProof = {
      approved: true,
      ownerUserId: ownerContext.userId,
      ownerEmailMasked,
      ownerRole: ownerContext.role,
      guardMode: ownerContext.guardMode,
      approvedAt: startedAt,
      mechanism: 'in_app_one_tap_owner_session',
    };

    // Stage 1 — trigger Render deploy
    let triggerStatus = 0;
    let triggerOk = false;
    let triggerParsed: unknown = null;
    try {
      const r = await fetch(`https://api.render.com/v1/services/${encodeURIComponent(serviceId)}/deploys`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json', Accept: 'application/json' },
        body: JSON.stringify({ clearCache }),
      });
      triggerStatus = r.status;
      triggerOk = r.ok;
      const text = await r.text();
      if (text) {
        try { triggerParsed = JSON.parse(text); } catch { triggerParsed = { raw: text.slice(0, 2000) }; }
      }
    } catch (err) {
      return ownerOnlyJson({
        ok: false,
        marker: IVX_AUTONOMY_MARKER,
        stage: 'render_trigger',
        approvalProof,
        error: err instanceof Error ? err.message : 'render_trigger_network_error',
      }, 502);
    }

    if (!triggerOk) {
      return ownerOnlyJson({
        ok: false,
        marker: IVX_AUTONOMY_MARKER,
        stage: 'render_trigger',
        approvalProof,
        renderHttpStatus: triggerStatus,
        renderResponse: triggerParsed,
      }, triggerStatus >= 400 && triggerStatus < 600 ? triggerStatus : 502);
    }

    const triggered = (triggerParsed && typeof triggerParsed === 'object' && 'deploy' in (triggerParsed as Record<string, unknown>))

  return new Response(null, {
    status: 204,
    headers: OWNER_ONLY_HEADERS,
  });
}

export async function assertIVXOwnerOnly(request: Request): Promise<IVXOwnerRequestContext> {
  if (checkIVXAISystemKey(request)) {
    return makeSystemOwnerRequestContext();
  }
  return await resolveIVXAuthenticatedRequest(request, '[IVXOwnerOnly]');
}

function normalizeOwnerEmail(value: unknown): string {
  return readIVXTrimmedString(value).toLowerCase();
}

function parseOwnerEmailAllowlist(value: unknown = process.env.IVX_OWNER_REGISTRATION_EMAILS): string[] {
  return Array.from(new Set(readIVXTrimmedString(value)
    .split(',')
    .map((email) => normalizeOwnerEmail(email))
    .filter((email) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email))));
}

function maskOwnerEmail(email: string | null): string | null {
  if (!email) return null;
  const [local = '', domain = ''] = email.split('@');
  if (!local || !domain) return '***';
  const visibleLocal = local.length <= 2 ? `${local.slice(0, 1)}*` : `${local.slice(0, 2)}***${local.slice(-1)}`;
  return `${visibleLocal}@${domain}`;
}

function makeOwnerMutationApprovalProof(input: {
  context: IVXAuthenticatedRequestContext | null;
  action: string;
  bearerAccepted: boolean;
  ownerVerified: boolean;
  ownerEmailMatched: boolean;
  allowlistConfigured: boolean;
  blocker: string | null;
}): IVXOwnerMutationApprovalProof {
  const email = normalizeOwnerEmail(input.context?.email ?? null) || null;
  return {
    ownerSessionDetected: Boolean(input.context?.userId && email),
    bearerAccepted: input.bearerAccepted,
    ownerVerified: input.ownerVerified,
    ownerEmailMatched: input.ownerEmailMatched,
    ownerEmailMasked: maskOwnerEmail(email),
    userId: input.context?.userId ?? null,
    role: input.context?.role ?? null,
    guardMode: input.context?.guardMode ?? null,
    allowlistConfigured: input.allowlistConfigured,
    action: input.action,
    blocker: input.blocker,
    secretValuesReturned: false,
  };
}

/**
 * Requires a real Supabase owner bearer and an email from IVX_OWNER_REGISTRATION_EMAILS.
 * This intentionally rejects the local/test open-access token for production mutations.
 */
export function evaluateIVXRegisteredOwnerBearerContext(
  context: IVXAuthenticatedRequestContext,
  action: string,
  ownerRegistrationEmailsValue: unknown = process.env.IVX_OWNER_REGISTRATION_EMAILS,
): IVXOwnerMutationApprovalEvaluation {
  const allowlist = parseOwnerEmailAllowlist(ownerRegistrationEmailsValue);
  const allowlistConfigured = allowlist.length > 0;
  const email = normalizeOwnerEmail(context.email);
  const tokenLooksLikeSupabaseJwt = context.accessToken.split('.').length === 3;
  const isExplicitDevToken = context.accessToken === IVX_OPEN_ACCESS_OWNER_TOKEN;
  const bearerAccepted = tokenLooksLikeSupabaseJwt && !isExplicitDevToken;
  const ownerEmailMatched = allowlistConfigured && allowlist.includes(email);
  const ownerVerified = bearerAccepted && ownerEmailMatched;

  if (!allowlistConfigured) {
    const blocker = 'IVX_OWNER_REGISTRATION_EMAILS is not configured in the backend runtime.';
    return {
      approved: false,
      status: 403,
      blocker,
      proof: makeOwnerMutationApprovalProof({ context, action, bearerAccepted, ownerVerified: false, ownerEmailMatched: false, allowlistConfigured, blocker }),
    };
  }

  if (!bearerAccepted) {
    const blocker = 'A real Supabase owner bearer token is required; local/test owner tokens are not accepted for senior-developer mutations.';
    return {
      approved: false,
      status: 401,
      blocker,
      proof: makeOwnerMutationApprovalProof({ context, action, bearerAccepted: false, ownerVerified: false, ownerEmailMatched, allowlistConfigured, blocker }),
    };
  }

  if (!ownerEmailMatched) {
    const blocker = 'Authenticated owner email is not listed in IVX_OWNER_REGISTRATION_EMAILS.';
    return {
      approved: false,
      status: 403,

    logPrefix,
    stage: 'allow',
    config,
    userId: IVX_OWNER_SERVICE_USER_ID,
    email: 'owner@ivx.holdings',
    roleAudit: serviceAudit,
    detail: 'Accepted configured IVX_OWNER_TOKEN owner service token.',
  });

  return {
    client: createIVXServerClient(accessToken),
    userId: IVX_OWNER_SERVICE_USER_ID,
    email: 'owner@ivx.holdings',
    role: 'owner',
    accessToken,
    guardMode: config.securityMode,
    roleAudit: serviceAudit,
  };
}

if (config.ownerBypassEnabled && accessToken === IVX_OPEN_ACCESS_OWNER_TOKEN) {
