    createdAt,
    finishedAt,
    duration: createdAt && finishedAt
      ? (new Date(finishedAt).getTime() - new Date(createdAt).getTime()) / 1000
      : null,
    failureReason: String(raw.failureReason ?? null) || null,
  };
}

